import json
from anthropic.types import ContentBlock

def serialize_content(content) -> str | list:
    """Convert SDK content objects to plain dicts for JSON storage."""
    if isinstance(content, str):
        return content
    if isinstance(content, list):
        result = []
        for block in content:
            if hasattr(block, "model_dump"):
                result.append(block.model_dump())
            elif isinstance(block, dict):
                result.append(block)
            else:
                result.append({"type": "text", "text": str(block)})
        return result
    return str(content)

def serialize_messages(messages: list) -> str:
    """Serialise a messages list (possibly containing SDK objects) to a JSON string."""
    plain = []
    for m in messages:
        plain.append({
            "role": m["role"] if isinstance(m, dict) else m.role,
            "content": serialize_content(m["content"] if isinstance(m, dict) else m.content),
        })
    return json.dumps(plain)

