from anthropic import Anthropic
import json

client = Anthropic()

def extract_key_facts(messages: list[dict]) -> list[str]:
    """Ask the model to extract durable facts from the conversation so far."""
    if len(messages) < 4:
        return []
    resp = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=200,
        messages=[{
            "role": "user",
            "content": (
                "Extract 3-5 key facts from this conversation that should be remembered. "
                "Return as JSON list of strings.\n\n"
                + json.dumps(messages[-10:])  # only look at recent turns
            )
        }]
    )
    try:
        return json.loads(resp.content[0].text)
    except (json.JSONDecodeError, IndexError):
        return []

def build_system_with_context(base_system: str, facts: list[str]) -> str:
    if not facts:
        return base_system
    facts_str = "\n".join(f"- {f}" for f in facts)
    return f"{base_system}\n\nKey facts from earlier in this session:\n{facts_str}"

# Pattern: every 10 turns, extract facts, store them, inject into system prompt
# This keeps the system prompt useful without growing the message list.
